enum PaymentStatus {
  success,
  failed,
  cancelled,
  pending,
  unknown,
}

class PaymentResult {
  final PaymentStatus status;
  final String? message;
  final String? transactionId;

  PaymentResult({required this.status, this.message, this.transactionId});
}

class PaymentService {
  static final PaymentService _instance = PaymentService._internal();
  factory PaymentService() => _instance;
  PaymentService._internal();

  final InAppPurchase _inAppPurchase = InAppPurchase.instance;
  late StreamSubscription<List<PurchaseDetails>> _purchaseStreamSubscription;
  final StreamController<PaymentResult> _purchaseResultController = StreamController.broadcast();
  Stream<PaymentResult> get purchaseResults => _purchaseResultController.stream;

  final BackendService _backendService = BackendService();

  Future<void> initialize({
    required String stripePublishableKey,
    required String stripeMerchantIdentifier, // Required for Apple Pay
  }) async {
    // Initialize In-App Purchase
    final bool isAvailable = await _inAppPurchase.isAvailable();
    if (isAvailable) {
      _purchaseStreamSubscription = _inAppPurchase.purchaseStream.listen(
        _onPurchaseUpdate,
        onDone: () => _purchaseStreamSubscription.cancel(),
        onError: (error) {
          _purchaseResultController.add(PaymentResult(status: PaymentStatus.failed, message: 'IAP Error: $error'));
        },
      );
    } else {
      debugPrint('In-App Purchases not available on this device.');
    }

    // Initialize Stripe SDK for card and mobile wallet payments
    Stripe.publishableKey = stripePublishableKey;
    Stripe.merchantIdentifier = stripeMerchantIdentifier;
    await Stripe.instance.applySettings();
  }

  void dispose() {
    _purchaseStreamSubscription.cancel();
    _purchaseResultController.close();
  }

  // --- In-App Purchases ---

  Future<List<ProductDetails>> getInAppProducts(Set<String> productIds) async {
    final ProductDetailsResponse response = await _inAppPurchase.queryProductDetails(productIds);
    if (response.error != null) {
      debugPrint('Error querying products: ${response.error!.message}');
      return [];
    }
    return response.productDetails;
  }

  Future<PaymentResult> purchaseInAppProduct(ProductDetails productDetails) async {
    final PurchaseParam purchaseParam = PurchaseParam(productDetails: productDetails);

    try {
      final bool purchaseInitiated = _inAppPurchase.buyNonConsumable(purchaseParam: purchaseParam); 
      // For consumables use _inAppPurchase.buyConsumable
      // For subscriptions use _inAppPurchase.buySubscription

      if (!purchaseInitiated) {
        return PaymentResult(status: PaymentStatus.failed, message: 'Failed to initiate purchase.');
      }
      return PaymentResult(status: PaymentStatus.pending, message: 'Purchase initiated, waiting for confirmation.');
    } catch (e) {
      return PaymentResult(status: PaymentStatus.failed, message: 'Purchase initiation failed: $e');
    }
  }

  void _onPurchaseUpdate(List<PurchaseDetails> purchaseDetailsList) {
    for (final PurchaseDetails purchaseDetails in purchaseDetailsList) {
      if (purchaseDetails.status == PurchaseStatus.pending) {
        _purchaseResultController.add(PaymentResult(status: PaymentStatus.pending, message: 'Purchase is pending.'));
      } else if (purchaseDetails.status == PurchaseStatus.error) {
        _purchaseResultController.add(PaymentResult(status: PaymentStatus.failed, message: purchaseDetails.error?.message ?? 'Purchase error.'));
        _inAppPurchase.completePurchase(purchaseDetails); 
      } else if (purchaseDetails.status == PurchaseStatus.purchased || purchaseDetails.status == PurchaseStatus.restored) {
        _handleSuccessfulPurchase(purchaseDetails);
      }
    }
  }

  Future<void> _handleSuccessfulPurchase(PurchaseDetails purchaseDetails) async {
    final bool verified = await _backendService.verifyInAppPurchase(purchaseDetails);

    if (verified) {
      _purchaseResultController.add(
        PaymentResult(
          status: PaymentStatus.success,
          message: 'Purchase successful!',
          transactionId: purchaseDetails.purchaseID,
        ),
      );
    } else {
      _purchaseResultController.add(
        PaymentResult(
          status: PaymentStatus.failed,
          message: 'Purchase verification failed. Please contact support.',
          transactionId: purchaseDetails.purchaseID,
        ),
      );
    }

    if (purchaseDetails.pendingCompletePurchase) {
      await _inAppPurchase.completePurchase(purchaseDetails);
    }
  }

  // --- Credit Card Payments (via Stripe) ---

  Future<PaymentResult> processCreditCardPayment({
    required String cardHolderName,
    required String cardNumber,
    required int expiryMonth,
    required int expiryYear,
    required String cvv,
    required double amount,
    required String currency,
    required String customerId,
  }) async {
    try {
      final paymentMethod = await Stripe.instance.createPaymentMethod(
        params: PaymentMethodParams.card(
          paymentMethodData: PaymentMethodData(
            billingDetails: BillingDetails(
              name: cardHolderName,
              // Add other billing details like address if required
            ),
          ),
