      );

      final clientSecret = await _backendService.createPaymentIntent(currency, amount, customerId);

      final paymentIntent = await Stripe.instance.confirmPayment(
        paymentIntentClientSecret: clientSecret,
        params: PaymentMethodParams.cardFromMethodId(
          paymentMethodData: PaymentMethodData(
            paymentMethodId: paymentMethod.id,
          ),
        ),
      );

      if (paymentIntent.status == PaymentIntentsStatus.Succeeded) {
        await _backendService.confirmBackendPayment(paymentIntent.id);
        return PaymentResult(status: PaymentStatus.success, message: 'Payment successful!', transactionId: paymentIntent.id);
      } else {
        return PaymentResult(status: PaymentStatus.failed, message: 'Payment failed with status: ${paymentIntent.status}');
      }
    } on StripeException catch (e) {
      return PaymentResult(status: PaymentStatus.failed, message: 'Stripe error: ${e.error.localizedMessage}');
    } catch (e) {
      return PaymentResult(status: PaymentStatus.failed, message: 'An unexpected error occurred: $e');
