  }

  // --- Apple Pay / Google Pay (via Stripe) ---

  Future<PaymentResult> processMobileWalletPayment({
    required double amount,
    required String currency,
    required String customerId,
    required String countryCode, 
    required List<
            ({String label, String amount})> items, // For Apple Pay breakdown
  }) async {
    try {
      if (Platform.isIOS && !await Stripe.instance.isApplePaySupported()) {
        return PaymentResult(status: PaymentStatus.failed, message: 'Apple Pay is not supported on this device.');
      }
      if (Platform.isAndroid && !await Stripe.instance.isGooglePaySupported()) {
        return PaymentResult(status: PaymentStatus.failed, message: 'Google Pay is not supported on this device.');
      }

      final clientSecret = await _backendService.createPaymentIntent(currency, amount, customerId);

      if (Platform.isIOS) {
        await Stripe.instance.presentApplePay(
          params: ApplePayPresentParams(
            clientSecret: clientSecret,
            country: countryCode, 
            currency: currency,
            requiredShippingAddressFields: {
              ApplePayContactFields.email,
              ApplePayContactFields.phoneNumber,
            },
            cartItems: items.map((item) => ApplePayCartItem(
              label: item.label,
              amount: item.amount,
              type: ApplePayCartItemType.final,
            )).toList(),
          ),
        );
      } else if (Platform.isAndroid) {
        await Stripe.instance.presentGooglePay(
          params: GooglePayPresentParams(
            clientSecret: clientSecret,
            countryCode: countryCode, 
            currencyCode: currency,
            forTesting: kDebugMode, 
            merchantName: 'Your Company Name',
          ),
        );
      }

      return PaymentResult(status: PaymentStatus.success, message: 'Mobile wallet payment successful!');

    } on StripeException catch (e) {
      if (e.error.code == 'Canceled') {
        return PaymentResult(status: PaymentStatus.cancelled, message: 'Payment cancelled.');
      }
      return PaymentResult(status: PaymentStatus.failed, message: 'Stripe error: ${e.error.localizedMessage}');
    } catch (e) {
      return PaymentResult(status: PaymentStatus.failed, message: 'An unexpected error occurred: $e');
    }
  }

